class UnionFind:
    def __init__(self, n):
        self.parent = list(range(n))
        self.rank = [0] * n
    def find(self, x):
        while self.parent[x] != x:
            self.parent[x] = self.parent[self.parent[x]]
            x = self.parent[x]
        return x
    def union(self, x, y):
        rx, ry = self.find(x), self.find(y)
        if rx == ry: return False
        if self.rank[rx] < self.rank[ry]: rx, ry = ry, rx
        self.parent[ry] = rx
        if self.rank[rx] == self.rank[ry]: self.rank[rx] += 1
        return True

def kruskal_mst(n, edges):
    edges = [(u, v, w) for u, v, w in edges if u != v]
    edges.sort(key=lambda e: e[2])
    uf = UnionFind(n)
    mst = []
    total = 0
    for u, v, w in edges:
        if uf.union(u, v):
            mst.append((u, v, w))
            total += w
    return (total, sorted(mst, key=lambda e: e[2]))

from heapq import heappush, heappop
from collections import defaultdict

def k_shortest_paths(n, edges, src, dst, k):
    adj = defaultdict(list)
    for u, v, w in edges:
        adj[u].append((v, w))
    counts = [0] * n
    results = []
    heap = [(0, src)]
    while heap and counts[dst] < k:
        dist, u = heappop(heap)
        counts[u] += 1
        if u == dst:
            results.append(dist)
            if len(results) == k:
                break
            continue
        if counts[u] > k:
            continue
        for v, w in adj[u]:
            heappush(heap, (dist + w, v))
    return sorted(results)

from collections import defaultdict, OrderedDict

class LFUCache:
    def __init__(self, capacity):
        self.cap = capacity
        self.min_freq = 0
        self.key_to_val = {}
        self.key_to_freq = {}
        self.freq_to_keys = defaultdict(OrderedDict)

    def _update_freq(self, key):
        freq = self.key_to_freq[key]
        self.freq_to_keys[freq].pop(key)
        if not self.freq_to_keys[freq]:
            del self.freq_to_keys[freq]
            if self.min_freq == freq:
                self.min_freq += 1
        self.key_to_freq[key] = freq + 1
        self.freq_to_keys[freq + 1][key] = None

    def get(self, key):
        if key not in self.key_to_val:
            return -1
        self._update_freq(key)
        return self.key_to_val[key]

    def put(self, key, value):
        if self.cap <= 0:
            return
        if key in self.key_to_val:
            self.key_to_val[key] = value
            self._update_freq(key)
            return
        if len(self.key_to_val) >= self.cap:
            evict_key, _ = self.freq_to_keys[self.min_freq].popitem(last=False)
            if not self.freq_to_keys[self.min_freq]:
                del self.freq_to_keys[self.min_freq]
            del self.key_to_val[evict_key]
            del self.key_to_freq[evict_key]
        self.key_to_val[key] = value
        self.key_to_freq[key] = 1
        self.freq_to_keys[1][key] = None
        self.min_freq = 1

from collections import defaultdict, deque

class TaskScheduler:
    def __init__(self):
        self.tasks = {}
        self.deps = defaultdict(set)
        self.completed = set()

    def add_task(self, task_id, priority):
        self.tasks[task_id] = priority

    def add_dependency(self, task_id, depends_on):
        self.deps[task_id].add(depends_on)

    def complete(self, task_id):
        self.completed.add(task_id)

    def _is_ready(self, task_id):
        return all(d in self.completed for d in self.deps[task_id])

    def get_next(self):
        ready = [(tid, self.tasks[tid]) for tid in self.tasks if tid not in self.completed and self._is_ready(tid)]
        if not ready:
            return None
        ready.sort(key=lambda x: (-x[1], x[0]))
        return ready[0][0]

    def get_order(self):
        in_deg = defaultdict(int)
        graph = defaultdict(set)
        all_tasks = set(self.tasks.keys())
        for tid in all_tasks:
            for dep in self.deps[tid]:
                if dep in all_tasks:
                    graph[dep].add(tid)
                    in_deg[tid] += 1
        available = []
        for tid in all_tasks:
            if in_deg[tid] == 0:
                available.append(tid)
        available.sort(key=lambda t: (-self.tasks[t], t))
        result = []
        while available:
            available.sort(key=lambda t: (-self.tasks[t], t))
            task = available.pop(0)
            result.append(task)
            for neighbor in graph[task]:
                in_deg[neighbor] -= 1
                if in_deg[neighbor] == 0:
                    available.append(neighbor)
        if len(result) != len(all_tasks):
            raise ValueError("Circular dependency detected")
        return result

