import bisect

class IntervalTracker:
    def __init__(self):
        self.intervals = []

    def add(self, start, end):
        if start >= end:
            return
        new = []
        inserted = False
        i = 0
        while i < len(self.intervals):
            s, e = self.intervals[i]
            if e < start:
                new.append((s, e))
            elif s > end:
                if not inserted:
                    new.append((start, end))
                    inserted = True
                new.append((s, e))
            else:
                start = min(start, s)
                end = max(end, e)
            i += 1
        if not inserted:
            new.append((start, end))
        self.intervals = new

    def remove(self, start, end):
        if start >= end:
            return
        new = []
        for s, e in self.intervals:
            if e <= start or s >= end:
                new.append((s, e))
            else:
                if s < start:
                    new.append((s, start))
                if e > end:
                    new.append((end, e))
        self.intervals = new

    def query(self, point):
        for s, e in self.intervals:
            if s <= point < e:
                return True
        return False

    def get_intervals(self):
        return list(self.intervals)

    def total_length(self):
        return sum(e - s for s, e in self.intervals)

from collections import deque
import bisect

class RateLimiter:
    def __init__(self, max_requests, window_seconds):
        self.max_req = max_requests
        self.window = window_seconds
        self.timestamps = []

    def _cleanup(self, now):
        cutoff = now - self.window
        idx = bisect.bisect_right(self.timestamps, cutoff)
        if idx > 0:
            self.timestamps = self.timestamps[idx:]

    def allow(self, timestamp):
        self._cleanup(timestamp)
        if len(self.timestamps) < self.max_req:
            self.timestamps.append(timestamp)
            return True
        return False

    def remaining(self, timestamp):
        self._cleanup(timestamp)
        return max(0, self.max_req - len(self.timestamps))

    def reset(self):
        self.timestamps = []

def parse_json(s):
    s = s.strip()
    val, pos = _parse_value(s, 0)
    pos = _skip_ws(s, pos)
    if pos != len(s):
        raise ValueError(f"Unexpected content at position {pos}")
    return val

def _skip_ws(s, pos):
    while pos < len(s) and s[pos] in ' \t\n\r':
        pos += 1
    return pos

def _parse_value(s, pos):
    pos = _skip_ws(s, pos)
    if pos >= len(s):
        raise ValueError("Unexpected end of input")
    c = s[pos]
    if c == '"':
        return _parse_string(s, pos)
    if c == '{':
        return _parse_object(s, pos)
    if c == '[':
        return _parse_array(s, pos)
    if s[pos:pos+4] == 'true':
        return True, pos + 4
    if s[pos:pos+5] == 'false':
        return False, pos + 5
    if s[pos:pos+4] == 'null':
        return None, pos + 4
    if c == '-' or c.isdigit():
        return _parse_number(s, pos)
    raise ValueError(f"Unexpected character '{c}' at position {pos}")

def _parse_string(s, pos):
    assert s[pos] == '"'
    pos += 1
    result = []
    while pos < len(s):
        c = s[pos]
        if c == '"':
            return ''.join(result), pos + 1
        if c == '\\':
            pos += 1
            if pos >= len(s):
                raise ValueError("Unexpected end in string escape")
            esc = s[pos]
            if esc == 'n': result.append('\n')
            elif esc == 't': result.append('\t')
            elif esc == '"': result.append('"')
            elif esc == '\\': result.append('\\')
            else: raise ValueError(f"Unknown escape: \\{esc}")
            pos += 1
        else:
            result.append(c)
            pos += 1
    raise ValueError("Unterminated string")

def _parse_number(s, pos):
    start = pos
    if s[pos] == '-':
        pos += 1
    if pos >= len(s) or not s[pos].isdigit():
        raise ValueError(f"Invalid number at {start}")
    while pos < len(s) and s[pos].isdigit():
        pos += 1
    is_float = False
    if pos < len(s) and s[pos] == '.':
        is_float = True
        pos += 1
        while pos < len(s) and s[pos].isdigit():
            pos += 1
    num_str = s[start:pos]
    return (float(num_str) if is_float else int(num_str)), pos

def _parse_array(s, pos):
    assert s[pos] == '['
    pos = _skip_ws(s, pos + 1)
    result = []
    if pos < len(s) and s[pos] == ']':
        return result, pos + 1
    while True:
        val, pos = _parse_value(s, pos)
        result.append(val)
        pos = _skip_ws(s, pos)
        if pos < len(s) and s[pos] == ']':
            return result, pos + 1
        if pos >= len(s) or s[pos] != ',':
            raise ValueError(f"Expected ',' or ']' at {pos}")
        pos += 1

def _parse_object(s, pos):
    assert s[pos] == '{'
    pos = _skip_ws(s, pos + 1)
    result = {}
    if pos < len(s) and s[pos] == '}':
        return result, pos + 1
    while True:
        pos = _skip_ws(s, pos)
        if pos >= len(s) or s[pos] != '"':
            raise ValueError(f"Expected string key at {pos}")
        key, pos = _parse_string(s, pos)
        pos = _skip_ws(s, pos)
        if pos >= len(s) or s[pos] != ':':
            raise ValueError(f"Expected ':' at {pos}")
        pos += 1
        val, pos = _parse_value(s, pos)
        result[key] = val
        pos = _skip_ws(s, pos)
        if pos < len(s) and s[pos] == '}':
            return result, pos + 1
        if pos >= len(s) or s[pos] != ',':
            raise ValueError(f"Expected ',' or '}}' at {pos}")
        pos += 1

def parse_csv(text, delimiter=',', quote_char='"'):
    rows = []
    row = []
    i = 0
    n = len(text)
    while i <= n:
        if i == n:
            if row or (rows and i > 0 and text[i-1] != '\n'):
                rows.append(row)
            break
        field, i = _parse_field(text, i, delimiter, quote_char)
        row.append(field)
        if i >= n:
            rows.append(row)
            break
        if text[i] == delimiter:
            i += 1
        elif text[i] == '\n':
            rows.append(row)
            row = []
            i += 1
            if i == n:
                break
        elif text[i] == '\r':
            i += 1
            if i < n and text[i] == '\n':
                i += 1
            rows.append(row)
            row = []
            if i == n:
                break
    return rows

def _parse_field(text, pos, delimiter, quote_char):
    if pos < len(text) and text[pos] == quote_char:
        return _parse_quoted(text, pos + 1, delimiter, quote_char)
    start = pos
    while pos < len(text) and text[pos] != delimiter and text[pos] != '\n' and text[pos] != '\r':
        pos += 1
    return text[start:pos], pos

def _parse_quoted(text, pos, delimiter, quote_char):
    result = []
    while pos < len(text):
        if text[pos] == quote_char:
            if pos + 1 < len(text) and text[pos + 1] == quote_char:
                result.append(quote_char)
                pos += 2
            else:
                pos += 1
                return ''.join(result), pos
        else:
            result.append(text[pos])
            pos += 1
    return ''.join(result), pos

class EventEmitter:
    def __init__(self):
        self._listeners = {}
        self._once_set = set()

    def on(self, event, callback):
        if event not in self._listeners:
            self._listeners[event] = []
        self._listeners[event].append(callback)
        def unsubscribe():
            self.off(event, callback)
        return unsubscribe

    def once(self, event, callback):
        self._once_set.add((event, id(callback)))
        wrapper = [None]
        def one_time(*args, **kwargs):
            callback(*args, **kwargs)
            self.off(event, wrapper[0])
        wrapper[0] = one_time
        one_time._original = callback
        return self.on(event, one_time)

    def emit(self, event, *args, **kwargs):
        cbs = list(self._listeners.get(event, []))
        wildcards = list(self._listeners.get('*', []))
        for cb in cbs + wildcards:
            cb(*args, **kwargs)

    def off(self, event, callback=None):
        if callback is None:
            self._listeners.pop(event, None)
        elif event in self._listeners:
            self._listeners[event] = [cb for cb in self._listeners[event] if cb != callback]
            if not self._listeners[event]:
                del self._listeners[event]

    def listeners(self, event):
        return list(self._listeners.get(event, []))

    def event_names(self):
        return sorted(e for e, cbs in self._listeners.items() if cbs)

class Matrix:
    def __init__(self, data):
        if not data or not data[0]:
            self.data = []
            self.rows = 0
            self.cols = 0
        else:
            self.data = [list(row) for row in data]
            self.rows = len(data)
            self.cols = len(data[0])

    def __repr__(self):
        return f"Matrix({self.data})"

    def __eq__(self, other):
        if not isinstance(other, Matrix):
            return False
        return self.data == other.data

    def __add__(self, other):
        if self.rows != other.rows or self.cols != other.cols:
            raise ValueError("Dimension mismatch")
        return Matrix([[self.data[i][j] + other.data[i][j] for j in range(self.cols)] for i in range(self.rows)])

    def __sub__(self, other):
        if self.rows != other.rows or self.cols != other.cols:
            raise ValueError("Dimension mismatch")
        return Matrix([[self.data[i][j] - other.data[i][j] for j in range(self.cols)] for i in range(self.rows)])

    def __mul__(self, other):
        if isinstance(other, (int, float)):
            return Matrix([[self.data[i][j] * other for j in range(self.cols)] for i in range(self.rows)])
        if self.cols != other.rows:
            raise ValueError("Dimension mismatch for multiplication")
        result = [[sum(self.data[i][k] * other.data[k][j] for k in range(self.cols)) for j in range(other.cols)] for i in range(self.rows)]
        return Matrix(result)

    def __rmul__(self, scalar):
        return self.__mul__(scalar)

    def transpose(self):
        return Matrix([[self.data[j][i] for j in range(self.rows)] for i in range(self.cols)])

    def determinant(self):
        if self.rows != self.cols:
            raise ValueError("Not square")
        return self._det(self.data)

    def _det(self, m):
        n = len(m)
        if n == 1:
            return m[0][0]
        if n == 2:
            return m[0][0]*m[1][1] - m[0][1]*m[1][0]
        det = 0
        for j in range(n):
            minor = [row[:j] + row[j+1:] for row in m[1:]]
            det += ((-1)**j) * m[0][j] * self._det(minor)
        return det

    def inverse(self):
        if self.rows != self.cols:
            raise ValueError("Not square")
        det = self.determinant()
        if det == 0:
            raise ValueError("Singular matrix")
        n = self.rows
        if n == 1:
            return Matrix([[1/det]])
        cofactors = []
        for i in range(n):
            row = []
            for j in range(n):
                minor = [r[:j]+r[j+1:] for r in (self.data[:i]+self.data[i+1:])]
                row.append(((-1)**(i+j)) * self._det(minor))
            cofactors.append(row)
        adjugate = Matrix(cofactors).transpose()
        return Matrix([[adjugate.data[i][j]/det for j in range(n)] for i in range(n)])
